anzetteln: [
	'<b>anzetteln</b>: instigate, incite, provoke'+
	'<br>Deutsch:&nbsp;&nbsp;<a href="https://www.duden.de/rechtschreibung/anzetteln"target="target1">anzetteln</a>&nbsp;&nbsp;<a href="https://www.dwds.de/wb/anzetteln"target="target2">anzetteln</a>'+
	'<br>English:&nbsp;&nbsp;&nbsp;<a href="https://en.langenscheidt.com/german-english/anzetteln"target="target3">anzetteln</a>&nbsp;&nbsp;<a href="https://www.verbformen.com/?w=anzetteln&id=verb%3Aanzetteln"target="target4">anzetteln</a>',
	'<u>Lunapark</u>',
	'"Walter Spindler", fuhr Pfeiffer fort, "hatte damals, in den Systemzeiten, als die Rotfront noch offen gegen die nationalsozialistische Bewegung SchlГӨgereien und Saalschlachten <b>anzettelte</b>, eine Masche, mit der er der Polizei immer wieder durch die Lappen ging. (<i>Lunapark</i>, 289)',
	'Die SA wollte putschen! Eine Riege rund um Stabschef RГ¶hm, dem zweitmГӨchtigsten Mann der Bewegung nach dem FГјhrer. Ausgerechnet der Duzfreund Adolf Hitlers, einer seiner ГӨltesten KampfgefГӨhrten, hatte ein VerschwГ¶rung <b>angezettelt</b>, die weit Гјber die Kreise der SA hinausreichte. (<i>Lunapark</i>, 468-69)',
],
preschen: [
	'(<b>vor</b>)<b>preschen</b>: rush, dash, tear'+
	'<br>Deutsch:&nbsp;&nbsp;<a href="https://www.duden.de/rechtschreibung/preschen"target="target1">preschen</a>&nbsp;&nbsp;<a href="https://www.dwds.de/wb/preschen"target="target2">preschen</a>'+
	'<br>English:&nbsp;&nbsp;&nbsp;<a href="https://en.langenscheidt.com/german-english/preschen"target="target3">preschen</a>&nbsp;&nbsp;<a href="https://www.verbformen.com/?w=preschen&id=verb%3Apreschen"target="target4">preschen</a>',
	'<u>Der nasse Fisch</u>',
	'Er (<i>ZГ¶rgiebel</i>) versuchte, ein paar Schritte zum Ausgang zu gehen, kam jedoch nicht weit, die Meute <b>preschte</b> wieder <b>vor</b>, die Fragen hagelten erneut... (<i>Der nasse Fisch</i>, 307)',
	'<u>Lunapark</u>',
	'Der schwarze Mercedes <b>preschte</b> durch Berlin. (<i>Lunapark</i>, 468)',
],
'unter Strom stehen': [
	'<b>unter Strom stehen</b>: run on adrenalin, be under pressure'+
	'<br>Deutsch:&nbsp;&nbsp;<a href="https://www.redensarten-index.de/suche.php?suchbegriff=unter+Strom+stehen&bool=relevanz&gawoe=an&sp0=rart_ou&sp1=rart_varianten_ou"target="target1">unter Strom stehen</a>&nbsp;&nbsp;<a href="https://www.wortbedeutung.info/unter_Strom_stehen/"target="target2">unter Strom stehen</a>'+
	'<br>English:&nbsp;&nbsp;&nbsp;<a href="https://hinative.com/questions/25109252"target="target3">unter Strom stehen</a>&nbsp;&nbsp;<a href="https://en.pons.com/translate/german-english/unter+Strom+stehen"target="target4">unter Strom stehen</a>',
	'<u>Lunapark</u>',
	'Er (<i>Rath</i>) <b>stand</b> vГ¶llig <b>unter Strom</b> und war doch zum Warten und Nichtstun verdammt, jedenfalls kam ihm das sinnlose WГјhlen in Akten vor wie Nichtstun - ein Zustand der ihn schier wahnsinnig machte. (<i>Lunapark</i>, 467-68)',
],
'Nacht um die Ohren schlagen': [
	'<b>sich die Nacht um die Ohren schlagen</b>: pull an all-nighter'+
	'<br>Deutsch:&nbsp;&nbsp;<a href="https://www.redensarten-index.de/suche.php?suchbegriff=um+die+Ohren+schlagen&bool=relevanz&gawoe=an&sp0=rart_ou&sp1=rart_varianten_ou"target="target1">Nacht um die Ohren schlagen</a>&nbsp;&nbsp;<a href="https://www.dwds.de/wb/sich%20die%20Nacht%20um%20die%20Ohren%20schlagen"target="target2">Nacht um die Ohren schlagen</a>'+
	'<br>English:&nbsp;&nbsp;&nbsp;<a href="https://www.dict.cc/?s=sich++die+Nacht+um+die+Ohren+schlagen"target="target3">Nacht um die Ohren schlagen</a>&nbsp;&nbsp;<a href="https://de.bab.la/woerterbuch/deutsch-englisch/die-nacht-um-die-ohren-schlagen"target="target4">Nacht um die Ohren schlagen</a>',
	'<u>Lunapark</u>',
	'Er (<i>Rath</i>) fragte sich, wie sicher Leo Jurtzka sich in solch einer Kolonie fГјhlen mochte. Und war dann auf die Idee gekommen, dass der Gangster sich auch hier wahrscheinlich nur im Schutze der Dunkelhiet auf das GelГӨnde wagte. Und genau deswegen hatte Rath sich nach Sonnenuntergang auf die Lauer gelegt. <b>Sich die halbe Nacht</b> im Auto <b>um die Ohren geschlagen</b>, ohne dass es zu etwas gefГјhrt hatte. (<i>Lunapark</i>, 466)',
],
Schablone: [
	'die <b>Schablone</b>,-<b>n</b>: pattern, model, template; clichГ©'+
	'<br>Deutsch:&nbsp;&nbsp;<a href="https://www.duden.de/rechtschreibung/Schablone"target="target1">Schablone</a>&nbsp;&nbsp;<a href="https://www.dwds.de/wb/Schablone"target="target2">Schablone</a>'+
	'<br>English:&nbsp;&nbsp;&nbsp;<a href="https://www.wordreference.com/deen/Schablone"target="target3">Schablone</a>&nbsp;&nbsp;<a href="https://www.verbformen.com/?w=Schablone&id=substantiv%3ASchablone"target="target4">Schablone</a>',
	'<u>Der nasse Fisch</u>',
	'UmstГӨndlich packte er (<i>der Schildermaler</i>) seine Farben, Pinsel und <b>Schablonen</b> aus und stellte sich vor die geГ¶ffnete TГјr. (<i>Der nasse Fisch</i>, 372)',
],
abspecken: [
	'<b>abspecken</b>: slim down, lose weight'+
	'<br>Deutsch:&nbsp;&nbsp;<a href="https://www.duden.de/rechtschreibung/abspecken"target="target1">abspecken</a>&nbsp;&nbsp;<a href="https://www.dwds.de/wb/abspecken"target="target2">abspecken</a>'+
	'<br>English:&nbsp;&nbsp;&nbsp;<a href="https://www.collinsdictionary.com/dictionary/german-english/abspecken"target="target3">abspecken</a>&nbsp;&nbsp;<a href="https://www.verbformen.com/?w=abspecken"target="target4">abspecken</a>',
	'<u>Der nasse Fisch</u>',
	'Um JГӨnickes MГ¶rder kГјmmmerte sich jetzt Gennat persГ¶nlich. Die Mordkommission <i>BГјlowplatz</i> war personell deutlich <b>abgespeckt</b> worden. Wobei <b>abspecken</b> vielleicht nicht der richtige Ausdruk war, wenn der Budda die Ermittlungen leitete. Gennat brachte mindestens drei Zentner auf die Waage. (<i>Der nasse Fisch</i>, 371)',
],
