Maulwurf: [
	'der <b>Maulwurf</b>,-<b>wГјrfe</b>: mole; spy, double agent'+
	'<br>Deutsch:&nbsp;&nbsp;<a href="https://www.duden.de/rechtschreibung/Maulwurf"target="target1">Maulwurf</a>&nbsp;&nbsp;<a href="https://www.dwds.de/wb/Maulwurf"target="target2">Maulwurf</a>'+
	'<br>English:&nbsp;&nbsp;&nbsp;<a href="https://en.langenscheidt.com/german-english/maulwurf"target="target3">Maulwurf</a>&nbsp;&nbsp;<a href="https://de.bab.la/woerterbuch/deutsch-englisch/maulwurf"target="target4">Maulwurf</a>',
	'<u>Lunapark</u>',
	'<i>Rath</i>: "Wenn ich einen Vorschlag machen darf, Kriminaldirektor: Wir sollten die ganze Sache zunГӨchst nicht an die groГҹe Glocke hГӨngen und den korrupten FJK-Offizier auГҹen vor lassen. Lassen Sie mich ausreichend Beweise sammeln, die eine Aushebung rechtfertigen. Dann schlagen wir zu, ohne dem <b>Maulwurf</b> im FJK Gelegenheit zu geben, seinen Freund Lapke zu warnen. Der Rest wird sich dann schon finden."   (<i>Lunapark</i>, 211)',
],
einstielen: [
	'<b>einstielen</b>: organize, set up'+
	'<br>Deutsch:&nbsp;&nbsp;<a href="https://www.duden.de/rechtschreibung/einstielen"target="target1">einstielen</a>&nbsp;&nbsp;<a href="https://www.dwds.de/wb/einstielen"target="target2">einstielen</a>'+
	'<br>English:&nbsp;&nbsp;&nbsp;<a href="https://en.pons.com/translate-2/german-english/einstielen"target="target3">einstielen</a>&nbsp;&nbsp;<a href="https://www.verbformen.com/?w=einstielen"target="target4">einstielen</a>',
	'<u>Lunapark</u>',
	'<i>Rath</i>: "Hermann Lapke persГ¶nlich leitet den Sturm hunderteins.. Wie ich das sehe, hat er die ganze Sache auch <b>eingestielt</b>, hat mithilfe seiner guten Kontakte zu jenem SturmbannfГјhrer Sperling dafГјr gesorgt, dass seine Piraten in die SA eintreten und den MaГҹnahmen zur Zerschlagung der Ringvereine entgehen konnten."   (<i>Lunapark</i>, 211)',
],
ungehalten: [
	'<b>ungehalten</b>: displeased, annoyed; indignant'+
	'<br>Deutsch:&nbsp;&nbsp;<a href="https://www.duden.de/rechtschreibung/ungehalten"target="target1">ungehalten</a>&nbsp;&nbsp;<a href="https://www.dwds.de/wb/ungehalten"target="target2">ungehalten</a>'+
	'<br>English:&nbsp;&nbsp;&nbsp;<a href="https://en.langenscheidt.com/german-english/ungehalten#sense-1.1.1"target="target3">ungehalten</a>&nbsp;&nbsp;<a href="https://context.reverso.net/translation/german-english/ungehalten"target="target4">ungehalten</a>',
	'<u>Der nasse Fisch</u>',
	'<i>Rath</i>: ".. Ich biete Ihnen an, aus dem Dienst auszuscheiden, um als Zeuge gegen Kirminaloberkommissar Wolter vor Gericht aufzutreten." <i>ZГ¶rgiebel</i>: "Jetzt hГ¶ren Sie doch endlich auf mit diesem BlГ¶dsinn! Den Dienst quittieren! Denken Sie nicht einmal im Traum daran! Das gestatte ich Ihnen nicht!" ZГ¶rgiebel wirkte <b>ungehalten</b>. (<i>Der nasse Fisch</i>, 505)',
	'<u>Der stumme Tod</u>',
	'Es klopfte, und Erika Voss steckte ihren blonden Schopf durch die TГјr. "Was ist denn?", fragte Rath <b>ungehalten</b> und hielt die Sprechmuschel zu. "Schon zurГјck vom ED? Ich will nicht gestГ¶rt werden!" (<i>Der stumme Tod</i>, 217)',
	'<u>Lunapark</u>',
	'Ernst Gennat wirkte <b>ungehalten</b>, Rath schon wieder auf seinem Sofa zu sehen. "Sollten Sie nicht bei der Staatspolizei sein? Wie ich gehГ¶rt habe, hat es am Sonnabend einen weiteren toten SA-Mann gegeben." (<i>Lunapark</i>, 210)',
	'Die Mettmann klopfte an die TГјr, und GrГӨf reagierte <b>ungehalten</b>. "Was ist denn noch?" (<i>Lunapark</i>, 407)',
	'<u>Marlow</u>',
	'<i>Rath</i>: ".. Es kГ¶nnte sein, dass Lehmann wegen seiner Beschwerden noch gar keinen Arzt konsultiert hat.".. "KГ¶nnte sein, kГ¶nnte sein.." Gennat wirkte <b>ungehalten</b>. "PrГјfen Sie das doch bitte nach, Oberkommissar. Sollte da irgendein Arzt geschlampt haben, hГӨtten wir ja eine ganz andere Schuldfrage." (<i>Marlow</i>, 89)',
],
