	'<br>English:&nbsp;&nbsp;&nbsp;<a href="https://en.langenscheidt.com/german-english/wuchern"target="target3">wuchern</a>&nbsp;&nbsp;<a href="https://www.verbformen.com/?w=%C3%BCberwuchern&id=verb%3Au3berwuchern"target="target4">Гјberwuchern</a>',
