	'<br>English:&nbsp;&nbsp;&nbsp;<a href="https://dictionary.cambridge.org/dictionary/german-english/zeug?q=was+das+Zeug+h%C3%A4lt"target="target3">was das Zeug hГӨlt</a>&nbsp;&nbsp;<a href="https://context.reverso.net/translation/german-english/was+das+Zeug+h%C3%A4lt"target="target4">was das Zeug hГӨlt</a>',
	'<u>MГӨrzgefallene</u>',
